\copy (SELECT A.as_of_year, A.respondent_id, Ag.agency_name, Ag.agency_abbr, R.agency_code, LT.loan_type_name, A.loan_type, PT.property_type_name, A.property_type, LP.loan_purpose_name, A.loan_purpose, OO.owner_occupancy_name, A.owner_occupancy, A.loan_amount_000s, PA.preapproval_name, A.preapproval, AT.action_taken_name, A.action_taken, M.msamd_name, L.msamd, S.state_name, S.state_abbr, L.state_code, C.county_name, L.county_code, L.census_tract_number, AE.applicant_ethnicity_name, A.applicant_ethnicity, CE.co_applicant_ethnicity_name, A.co_applicant_ethnicity, R1.race_name AS applicant_race_name_1, AR1.applicant_race_code AS applicant_race_1, R2.race_name AS applicant_race_name_2, AR2.applicant_race_code AS applicant_race_2, R3.race_name AS applicant_race_name_3, AR3.applicant_race_code AS applicant_race_3, R4.race_name AS applicant_race_name_4, AR4.applicant_race_code AS applicant_race_4, R5.race_name AS applicant_race_name_5, AR5.applicant_race_code AS applicant_race_5, CR1.race_name AS co_applicant_race_name_1, CAR1.co_applicant_race_code AS co_applicant_race_1, CR2.race_name AS co_applicant_race_name_2, CAR2.co_applicant_race_code AS co_applicant_race_2, CR3.race_name AS co_applicant_race_name_3, CAR3.co_applicant_race_code AS co_applicant_race_3, CR4.race_name AS co_applicant_race_name_4, CAR4.co_applicant_race_code AS co_applicant_race_4, CR5.race_name AS co_applicant_race_name_5, CAR5.co_applicant_race_code AS co_applicant_race_5, ASex.applicant_sex_name, A.applicant_sex, CSex.co_applicant_sex_name, A.co_applicant_sex, A.applicant_income_000s, Pur.purchaser_type_name, A.purchaser_type, DR1.denial_reason_name AS denial_reason_name_1, D1.denial_reason AS denial_reason_1, DR2.denial_reason_name AS denial_reason_name_2, D2.denial_reason AS denial_reason_2, DR3.denial_reason_name AS denial_reason_name_3, D3.denial_reason AS denial_reason_3, A.rate_spread, HS.hoepa_status_name, A.hoepa_status, LS.lien_status_name, A.lien_status, ES.edit_status_name, A.edit_status, A.sequence_number, L.population, L.minority_population, L.hud_median_family_income, L.tract_to_msamd_income, L.number_of_owner_occupied_units, L.number_of_1_to_4_family_units, A.application_date_indicator FROM Application A LEFT JOIN Respondent R ON A.respondent_id = R.respondent_id LEFT JOIN Agency Ag ON R.agency_code = Ag.agency_code LEFT JOIN Loan_Type LT ON A.loan_type = LT.loan_type LEFT JOIN Property_Type PT ON A.property_type = PT.property_type LEFT JOIN Loan_Purpose LP ON A.loan_purpose = LP.loan_purpose LEFT JOIN Owner_Occupancy OO ON A.owner_occupancy = OO.owner_occupancy LEFT JOIN Preapproval PA ON A.preapproval = PA.preapproval LEFT JOIN Action_Taken AT ON A.action_taken = AT.action_taken LEFT JOIN Location L ON A.LocationID = L.LocationID LEFT JOIN Msamd M ON L.msamd = M.msamd LEFT JOIN State S ON L.state_code = S.state_code LEFT JOIN County C ON L.county_code = C.county_code LEFT JOIN Applicant_Ethnicity AE ON A.applicant_ethnicity = AE.applicant_ethnicity LEFT JOIN Co_Applicant_Ethnicity CE ON A.co_applicant_ethnicity = CE.co_applicant_ethnicity LEFT JOIN Applicant_Sex ASex ON A.applicant_sex = ASex.applicant_sex LEFT JOIN Co_Applicant_Sex CSex ON A.co_applicant_sex = CSex.co_applicant_sex LEFT JOIN Purchaser_Type Pur ON A.purchaser_type = Pur.purchaser_type LEFT JOIN Hoepa_Status HS ON A.hoepa_status = HS.hoepa_status LEFT JOIN Lien_Status LS ON A.lien_status = LS.lien_status LEFT JOIN Edit_Status ES ON A.edit_status = ES.edit_status LEFT JOIN Applicant_Race AR1 ON A.ApplicationID = AR1.ApplicationID AND AR1.applicant_race_number = 1 LEFT JOIN Race R1 ON AR1.applicant_race_code = R1.race_code LEFT JOIN Applicant_Race AR2 ON A.ApplicationID = AR2.ApplicationID AND AR2.applicant_race_number = 2 LEFT JOIN Race R2 ON AR2.applicant_race_code = R2.race_code LEFT JOIN Applicant_Race AR3 ON A.ApplicationID = AR3.ApplicationID AND AR3.applicant_race_number = 3 LEFT JOIN Race R3 ON AR3.applicant_race_code = R3.race_code LEFT JOIN Applicant_Race AR4 ON A.ApplicationID = AR4.ApplicationID AND AR4.applicant_race_number = 4 LEFT JOIN Race R4 ON AR4.applicant_race_code = R4.race_code LEFT JOIN Applicant_Race AR5 ON A.ApplicationID = AR5.ApplicationID AND AR5.applicant_race_number = 5 LEFT JOIN Race R5 ON AR5.applicant_race_code = R5.race_code LEFT JOIN Co_Applicant_Race CAR1 ON A.ApplicationID = CAR1.ApplicationID AND CAR1.co_applicant_race_number = 1 LEFT JOIN Race CR1 ON CAR1.co_applicant_race_code = CR1.race_code LEFT JOIN Co_Applicant_Race CAR2 ON A.ApplicationID = CAR2.ApplicationID AND CAR2.co_applicant_race_number = 2 LEFT JOIN Race CR2 ON CAR2.co_applicant_race_code = CR2.race_code LEFT JOIN Co_Applicant_Race CAR3 ON A.ApplicationID = CAR3.ApplicationID AND CAR3.co_applicant_race_number = 3 LEFT JOIN Race CR3 ON CAR3.co_applicant_race_code = CR3.race_code LEFT JOIN Co_Applicant_Race CAR4 ON A.ApplicationID = CAR4.ApplicationID AND CAR4.co_applicant_race_number = 4 LEFT JOIN Race CR4 ON CAR4.co_applicant_race_code = CR4.race_code LEFT JOIN Co_Applicant_Race CAR5 ON A.ApplicationID = CAR5.ApplicationID AND CAR5.co_applicant_race_number = 5 LEFT JOIN Race CR5 ON CAR5.co_applicant_race_code = CR5.race_code LEFT JOIN Denial D1 ON A.ApplicationID = D1.ApplicationID AND D1.denial_reason_number = 1 LEFT JOIN Denial_Reason DR1 ON D1.denial_reason = DR1.denial_reason LEFT JOIN Denial D2 ON A.ApplicationID = D2.ApplicationID AND D2.denial_reason_number = 2 LEFT JOIN Denial_Reason DR2 ON D2.denial_reason = DR2.denial_reason LEFT JOIN Denial D3 ON A.ApplicationID = D3.ApplicationID AND D3.denial_reason_number = 3 LEFT JOIN Denial_Reason DR3 ON D3.denial_reason = DR3.denial_reason) TO 'reconstructed_hmda.csv' WITH CSV HEADER;
-- This was all on one line since \copy was very finnicky with multiple lines